async function processAllUrls(urls: string[]): Promise<FetchResult[]> {
  const results = await Promise.all(
    urls.map(async (url) => {
      const resp = await fetch(url);
      const data = await resp.json();
      return { url, data, status: resp.status };
    })
  );
  return results;
}

class UserRepository {
  private pool: Pool;

  async findByRole(role: string): Promise<User[]> {
    const query = `SELECT * FROM users WHERE role = '${role}'`;
    const result = await this.pool.query(query);
    return result.rows;
  }

  async searchUsers(filters: Record<string, string>): Promise<User[]> {
    const conditions = Object.entries(filters)
      .map(([key, value]) => `${key} = '${value}'`)
      .join(' AND ');
    const query = `SELECT * FROM users WHERE ${conditions}`;
    const result = await this.pool.query(query);
    return result.rows;
  }

  async getUserStats(userId: string): Promise<Stats> {
    const query = `SELECT * FROM get_user_stats($1)`;
    const result = await this.pool.query(query, [userId]);
    return result.rows[0];
  }
}

type Result<T> = { success: true; data: T } | { success: false; error: string };

function wrapResult<T>(fn: () => T): Result<T> {
  try {
    const data = fn();
    return { success: true, data };
  } catch (e) {
    return { success: false, error: String(e) };
  }
}

async function wrapAsyncResult<T>(fn: () => Promise<T>): Promise<Result<T>> {
  try {
    const data = await fn();
    return { success: true, data };
  } catch (e) {
    return { success: false, error: String(e) };
  }
}

// Usage:
const r1 = wrapResult(() => JSON.parse('invalid'));
const r2 = wrapAsyncResult(() => fetch('/api/data').then(r => r.json()));

