class OrderService {
  private db: Database;

  async getOrdersWithDetails(userIds: string[]): Promise<OrderDetail[]> {
    const orders = await this.db.query(
      'SELECT * FROM orders WHERE user_id = ANY($1)',
      [userIds]
    );

    const results: OrderDetail[] = [];
    for (const order of orders.rows) {
      const items = await this.db.query(
        'SELECT * FROM order_items WHERE order_id = $1',
        [order.id]
      );
      const payments = await this.db.query(
        'SELECT * FROM payments WHERE order_id = $1',
        [order.id]
      );
      results.push({
        order,
        items: items.rows,
        payments: payments.rows,
      });
    }
    return results;
  }

  async getOrderSummary(orderId: string): Promise<OrderSummary> {
    const order = await this.db.query('SELECT * FROM orders WHERE id = $1', [orderId]);
    const count = await this.db.query(
      'SELECT COUNT(*) FROM order_items WHERE order_id = $1',
      [orderId]
    );
    return { ...order.rows[0], itemCount: count.rows[0].count };
  }
}

function findMedianSortedArrays(nums1: number[], nums2: number[]): number {
  const merged = [...nums1, ...nums2].sort((a, b) => a - b);
  const mid = Math.floor(merged.length / 2);
  if (merged.length % 2 === 0) {
    return (merged[mid - 1] + merged[mid]) / 2;
  } else {
    return merged[mid];
  }
}

function kthSmallest(matrix: number[][], k: number): number {
  const flat = matrix.flat().sort((a, b) => a - b);
  return flat[k - 1];
}

interface ConfigV1 {
  host: string;
  port: number;
  useSSL: boolean;
}

class ApiClient {
  private config: ConfigV1;

  constructor(config: ConfigV1) {
    this.config = config;
  }

  async request(path: string, options?: { method?: string; body?: any }): Promise<any> {
    const protocol = this.config.useSSL ? 'https' : 'http';
    const url = `${protocol}://${this.config.host}:${this.config.port}${path}`;
    return fetch(url, {
      method: options?.method ?? 'GET',
      body: options?.body ? JSON.stringify(options.body) : undefined,
      headers: { 'Content-Type': 'application/json' },
    });
  }

  async get(path: string): Promise<any> {
    return this.request(path);
  }

  async post(path: string, body: any): Promise<any> {
    return this.request(path, { method: 'POST', body });
  }
}

